var fs = require("fs");
var crypto = require("crypto");
var path = require("path");

exports.writeFile = function(filePath, data, options, callback) {
    if (typeof options == "function") {
        callback = options;
        options = null;
    }

    var tmpFile = path.join(path.dirname(filePath), "." + crypto.randomBytes(8).toString("hex") + ".tmp");

    fs.writeFile(tmpFile, data, options, function(err) {
        if (err) return callback(err);
        fs.rename(tmpFile, filePath, function(err) {
            if (err) {
                fs.unlink(tmpFile, function() { callback(err); });
            } else {
                callback(null);
            }
        });
    });
};
